{"code": "import json

# Check what variables are available
available_vars = list(locals().keys())
print('='*50)
print("AVAILABLE VARIABLES:")
print(available_vars)
print('='*50)

# Find the business data variable (likely ends with :5)
business_data_var = None
for var in available_vars:
    if 'query_db:5' in var:
        business_data_var = var
        print(f"Found business data variable: {var}")
        break

if not business_data_var:
    print("No business data found in variables")
    result = {'status': 'no_data_variable'}
else:
    # Access the business data
    business_data = locals()[business_data_var]
    print(f"Data type: {type(business_data)}")
    print(f"Data length: {len(business_data)}")

    # Let's examine one sample business
    if len(business_data) > 0:
        first_biz = business_data[0]
        print(f"\nSample business: {first_biz}")

    # More detailed analysis
    total_wifi = 0
    wifi_values = []
    state_counts = {}

    print(f"\nAnalyzing {len(business_data)} businesses...")

    for i, business in enumerate(business_data):
        # Check if attributes exist and contain WiFi info
        attrs = business.get('attributes')
        has_wifi = False
        wifi_val = None

        if isinstance(attrs, dict):
            # Check for WiFi in attributes
            for key, value in attrs.items():
                if 'wifi' in str(key).lower() or 'WiFi' in key:
                    wifi_val = str(value)
                    has_wifi = True
                    wifi_values.append(wifi_val)
                    break

        # Extract state from description
        state = None
        desc = business.get('description', '')

        # Look for pattern: "..., State ..." or "... in City, State"
        if ', ' in desc:
            parts = desc.rsplit(', ', 1)  # Split from the right
            if len(parts) == 2:
                potential_state = parts[1].strip()
                # Extract just the 2-letter state code if present
                state_words = potential_state.split()
                if state_words:
                    # Check if first word is 2 letters and uppercase
                    if len(state_words[0]) == 2 and state_words[0].isalpha():
                        state = state_words[0]

        if has_wifi and state:
            total_wifi += 1
            state_counts[state] = state_counts.get(state, 0) + 1

        # Progress indicator
        if (i + 1) % 1000 == 0:
            print(f"Processed {i + 1} businesses...")

    print(f"\n=== FINAL RESULTS ===")
    print(f"Total businesses with WiFi: {total_wifi}")
    print(f"Top 10 states:")

    # Sort by count
    sorted_states = sorted(state_counts.items(), key=lambda x: x[1], reverse=True)[:10]
    for state, count in sorted_states:
        print(f"  {state}: {count} businesses")

    # Get the state with highest WiFi businesses
    top_state = None
    if state_counts:
        top_state = max(state_counts.items(), key=lambda x: x[1])
        print(f"Top state: {top_state[0]} with {top_state[1]} businesses")

    # Get the business IDs for the top state
    top_businesses = []
    if top_state:
        for business in business_data:
            attrs = business.get('attributes')
            has_wifi = False
            if isinstance(attrs, dict):
                for key, value in attrs.items():
                    if 'wifi' in str(key).lower() or 'WiFi' in key:
                        if 'no' not in str(value).lower():
                            has_wifi = True

            if has_wifi:
                desc = business.get('description', '')
                if ', ' in desc:
                    parts = desc.rsplit(', ', 1)
                    if len(parts) == 2:
                        potential_state = parts[1].strip()
                        state_words = potential_state.split()
                        if state_words and len(state_words[0]) == 2 and state_words[0].isalpha():
                            biz_state = state_words[0]
                            if biz_state == top_state[0]:
                                top_businesses.append(business['business_id'])

    result = {
        'total_businesses_analyzed': len(business_data),
        'businesses_with_wifi': total_wifi,
        'top_state': top_state[0] if top_state else None,
        'top_state_count': top_state[1] if top_state else 0,
        'top_10_states': dict(sorted_states),
        'sample_business_ids': top_businesses[:10]
    }

print('__RESULT__:')
print(json.dumps(result))"}

